SELECT [VendutoCompratoProiezione-step6-VenditeProiettate].No_, [VendutoCompratoProiezione-step6-VenditeProiettate].[Constant Variable Code], [VendutoCompratoProiezione-step6-VenditeProiettate].PairsSold, [VendutoCompratoProiezione-step8-CompratoByAricoloColore].PairsPurchased, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsByMarket_, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsByMarketCorrected_, [VendutoCompratoProiezione-step6-VenditeProiettate].ForecastedPairsFlat, IIf([pairssold]-[pairspurchased]>0,[pairssold]-[pairspurchased],0) AS toBuy, IIf([pairssold]-[pairspurchased]<=0,[pairssold]-[pairspurchased],0) AS toSell, IIf([ForecastedPairsByMarketCorrected_]-[pairspurchased]>0,[ForecastedPairsByMarketCorrected_]-[pairspurchased],0) AS toBuyByBudgetCorrected, IIf([ForecastedPairsByMarketCorrected_]-[pairspurchased]<=0,[ForecastedPairsByMarketCorrected_]-[pairspurchased],0) AS toSellByBudgetCorrected, IIf([ForecastedPairsFlat]-[pairspurchased]>0,[ForecastedPairsFlat]-[pairspurchased],0) AS toBuyFlat, IIf([ForecastedPairsFlat]-[pairspurchased]<=0,[ForecastedPairsFlat]-[pairspurchased],0) AS toSellFlat
FROM [VendutoCompratoProiezione-step6-VenditeProiettate] INNER JOIN [VendutoCompratoProiezione-step8-CompratoByAricoloColore] ON ([VendutoCompratoProiezione-step6-VenditeProiettate].[Constant Variable Code] = [VendutoCompratoProiezione-step8-CompratoByAricoloColore].[Constant Variable Code]) AND ([VendutoCompratoProiezione-step6-VenditeProiettate].No_ = [VendutoCompratoProiezione-step8-CompratoByAricoloColore].No_);

